  const finalResolved = path.resolve(candidatePath);

  // Ensure final path is within base directory (prefix match with path separator boundary).
  const baseWithSep = baseResolved.endsWith(path.sep) ? baseResolved : baseResolved + path.sep;
  if (finalResolved !== baseResolved && !finalResolved.startsWith(baseWithSep)) {
    throw new Error('Resolved path escapes base directory');
  }

  // Ensure category directory exists.
  const categoryDir = path.resolve(path.join(BASE_DIR, category));
  if (categoryDir !== baseResolved && !categoryDir.startsWith(baseWithSep)) {
    throw new Error('Resolved category path escapes base directory');
  }
  fs.mkdirSync(categoryDir, { recursive: true, mode: 0o700 });

  // Write snapshot data.
  fs.writeFileSync(finalResolved, data, { encoding: 'utf8', mode: 0o600, flag: 'w' });
}

module.exports = { saveDataSnapshot };
